module RefModule(
    input CLOCK,
    input signed [31:0] pc,
    output signed [31:0] pcout
);reg signed [31:0] pc1, pc2, pc3,pc4;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLOCK or posedge dbg_halt) begin
pc1 <= pc;
pc2 <= pc1 + 4;
pc3 <= pc2;
pc4 <= pc3; 
end

assign pcout[31:0] = pc4;

endmodule
